patch:
--- a/comparator.v
+++ b/comparator.v
@@ -1,11 +1,11 @@
 module magnitude_comp(
   input [31:0] a_val, b_val,
   output reg eq_flag, lt_flag, gt_flag
 );
-  always @(a_val)
+  always @(*)
   begin
     if (a_val == b_val)
       eq_flag = 1'b1;
     else
       eq_flag = 1'b0;

before_code:
module magnitude_comp(
  input [31:0] a_val, b_val,
  output reg eq_flag, lt_flag, gt_flag
);
  always @(a_val)
  begin
    if (a_val == b_val)
      eq_flag = 1'b1;
    else
      eq_flag = 1'b0;

    if (a_val < b_val)
      lt_flag = 1'b1;
    else
      lt_flag = 1'b0;

    if (a_val > b_val)
      gt_flag = 1'b1;
    else
      gt_flag = 1'b0;
  end
endmodule

after_code:
module magnitude_comp(
  input [31:0] a_val, b_val,
  output reg eq_flag, lt_flag, gt_flag
);
  always @(*)
  begin
    if (a_val == b_val)
      eq_flag = 1'b1;
    else
      eq_flag = 1'b0;

    if (a_val < b_val)
      lt_flag = 1'b1;
    else
      lt_flag = 1'b0;

    if (a_val > b_val)
      gt_flag = 1'b1;
    else
      gt_flag = 1'b0;
  end
endmodule
